import{_ as t,o as s,c as r,a2 as a}from"./chunks/framework.D5wUhsuj.js";const g=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/index.md","filePath":"troubleshooting/index.md"}'),o={name:"troubleshooting/index.md"};function n(i,e,d,l,h,c){return s(),r("div",null,[...e[0]||(e[0]=[a(`<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>Find your symptom below. Each row links to the specific fix — you don&#39;t need to read a whole page to solve one problem.</p><h2 id="by-symptom" tabindex="-1">By symptom <a class="header-anchor" href="#by-symptom" aria-label="Permalink to &quot;By symptom&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Likely cause</th><th>Go to</th></tr></thead><tbody><tr><td><strong>502 Bad Gateway</strong></td><td>PHP-FPM crashed, wrong socket path, or a plugin/script fatally erroring</td><td><a href="/docs/troubleshooting/server-errors#502-bad-gateway">Server Errors</a></td></tr><tr><td><strong>503 Service Unavailable</strong></td><td>PHP-FPM pool overwhelmed, or a service was mid-restart</td><td><a href="/docs/troubleshooting/server-errors#503-service-unavailable">Server Errors</a></td></tr><tr><td><strong>500 Internal Server Error / white screen</strong></td><td>PHP fatal error — usually a plugin, theme, or <code>.htaccess</code>-equivalent issue</td><td><a href="/docs/troubleshooting/server-errors#500-internal-server-error-white-screen">Server Errors</a></td></tr><tr><td><strong>504 Gateway Timeout</strong></td><td>A request is taking longer than PHP-FPM&#39;s timeout to finish</td><td><a href="/docs/troubleshooting/server-errors#504-gateway-timeout">Server Errors</a></td></tr><tr><td><strong>502 right after switching PHP versions</strong></td><td>Vhost still pointing at the old version&#39;s socket</td><td><a href="/docs/troubleshooting/server-errors#502-right-after-switching-php-versions">Server Errors</a></td></tr><tr><td><strong>&quot;This site can&#39;t be reached&quot; / DNS error</strong></td><td>DNS not pointed at the server, or hasn&#39;t propagated yet</td><td><a href="/docs/troubleshooting/domain-ssl#dns-not-resolving">Domain &amp; SSL Issues</a></td></tr><tr><td><strong>Browser SSL warning on the panel (port 8443)</strong></td><td>Expected — the panel UI uses a self-signed cert</td><td><a href="/docs/troubleshooting/domain-ssl#browser-warning-on-the-panel-port-8443">Domain &amp; SSL Issues</a></td></tr><tr><td><strong>Browser SSL warning on your actual site</strong></td><td>SSL not installed yet, or the cert doesn&#39;t cover <code>www</code></td><td><a href="/docs/troubleshooting/domain-ssl#browser-warning-on-your-site">Domain &amp; SSL Issues</a></td></tr><tr><td><strong><code>ssl:install</code> fails with &quot;challenge failed&quot;</strong></td><td>Port 80 blocked, or DNS not propagated</td><td><a href="/docs/troubleshooting/domain-ssl#challenge-failed">Domain &amp; SSL Issues</a></td></tr><tr><td><strong>&quot;Too many certificates&quot; error</strong></td><td>Hit Let&#39;s Encrypt&#39;s rate limit while testing</td><td><a href="/docs/troubleshooting/domain-ssl#too-many-certificates">Domain &amp; SSL Issues</a></td></tr><tr><td><strong>Edited a post/menu but the live site didn&#39;t change</strong></td><td>FastCGI Cache serving a stale page</td><td><a href="/docs/troubleshooting/cache-performance#change-not-showing-up">Cache &amp; Performance</a></td></tr><tr><td><strong>Site feels slow despite cache being on</strong></td><td>Low hit rate, or cache not actually enabled for that domain</td><td><a href="/docs/troubleshooting/cache-performance#slow-despite-cache-being-on">Cache &amp; Performance</a></td></tr><tr><td><strong>Logged-in users seeing cached/stale content</strong></td><td>Expected — logged-in traffic always bypasses cache, this is a different problem</td><td><a href="/docs/troubleshooting/cache-performance#logged-in-users-and-cache">Cache &amp; Performance</a></td></tr><tr><td><strong>&quot;Error establishing a database connection&quot;</strong></td><td>Wrong DB credentials in <code>wp-config.php</code>/<code>.env</code>, or MySQL/MariaDB is down</td><td><a href="/docs/troubleshooting/permissions-database#error-establishing-a-database-connection">Permissions &amp; Database</a></td></tr><tr><td><strong>Can&#39;t upload images / plugin install fails (&quot;unable to create directory&quot;)</strong></td><td>File ownership wrong after a manual file transfer</td><td><a href="/docs/troubleshooting/permissions-database#upload-failures">Permissions &amp; Database</a></td></tr><tr><td><strong>403 Forbidden</strong></td><td>Permission bits too restrictive, or an Nginx <code>deny</code> rule matching unexpectedly</td><td><a href="/docs/troubleshooting/permissions-database#403-forbidden">Permissions &amp; Database</a></td></tr><tr><td><strong><code>site:delete --purge</code> refuses to remove a user</strong></td><td>The <code>.aidipanel-managed</code> marker is missing or was edited</td><td><a href="/docs/troubleshooting/permissions-database#guarded-delete-refuses-to-run">Permissions &amp; Database</a></td></tr></tbody></table><h2 id="by-area" tabindex="-1">By area <a class="header-anchor" href="#by-area" aria-label="Permalink to &quot;By area&quot;">​</a></h2><div class="ap-cards"><p><strong><a href="/docs/troubleshooting/server-errors">Server &amp; Gateway Errors →</a></strong> 502, 503, 500, 504 — the HTTP error codes that mean &quot;something upstream broke.&quot;</p><p><strong><a href="/docs/troubleshooting/domain-ssl">Domain &amp; SSL Issues →</a></strong> DNS propagation, certificate installation, browser warnings, rate limits.</p><p><strong><a href="/docs/troubleshooting/cache-performance">Cache &amp; Performance →</a></strong> Stale content, purge behavior, hit rate, and general speed troubleshooting.</p><p><strong><a href="/docs/troubleshooting/permissions-database">Permissions &amp; Database →</a></strong> File ownership, upload failures, database connection errors, guarded delete.</p></div><h2 id="general-first-steps-for-anything" tabindex="-1">General first steps for anything <a class="header-anchor" href="#general-first-steps-for-anything" aria-label="Permalink to &quot;General first steps for anything&quot;">​</a></h2><p>Before diving into a specific page, these two commands answer &quot;is it actually broken, and where&quot;:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Is everything actually running?</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service:status</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># What does this site&#39;s own error log say? (usually the fastest answer)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log:tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> error</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>The per-site error log especially — <code>/var/log/nginx/&lt;domain&gt;-error.log</code> — will usually name the exact problem (a missing PHP extension, a permission-denied path, a timeout) rather than leaving you to guess from just the HTTP status code.</p>`,10)])])}const u=t(o,[["render",n]]);export{g as __pageData,u as default};
